+fn path_from_simple_shell_command(command: &str, prefix: &str) -> Option<PathBuf> {
+    let raw = command.strip_prefix(prefix)?.trim();
+    decode_shell_single_argument(raw).map(PathBuf::from)
+}
+
+fn decode_shell_single_argument(raw: &str) -> Option<String> {
+    let raw = raw.trim();
+    if raw.is_empty() {
+        return None;
+    }
+
+    let mut out = String::new();
+    let chars: Vec<char> = raw.chars().collect();
+    let mut idx = 0usize;
+
+    while idx < chars.len() {
+        match chars[idx] {
+            '\'' => {
+                idx += 1;
+                while idx < chars.len() && chars[idx] != '\'' {
+                    out.push(chars[idx]);
+                    idx += 1;
+                }
+                if idx >= chars.len() {
+                    return None;
+                }
+                idx += 1;
+            }
+            '\\' => {
+                idx += 1;
+                if idx >= chars.len() {
+                    return None;
+                }
+                out.push(chars[idx]);
+                idx += 1;
+            }
+            c if c.is_whitespace() => {
+                if chars[idx..].iter().all(|ch| ch.is_whitespace()) {
+                    return Some(out);
+                }
+                return None;
+            }
+            c => {
+                out.push(c);
+                idx += 1;
+            }
+        }
+    }
+
+    Some(out)
+}
